---游戏更新控制器

local LxBehaviour = require("LApp.component.LxBehaviour")
---@class LxPatchCtrl:LxBehaviour
local LxPatchCtrl = classX("LxPatchCtrl", LxBehaviour)

local _Steps = {
    None = 0,
    WaitSdkInit = 1,
    WaitHost = 2,
    WaitUpdateServerInfo = 3,
    CheckUpdate = 4,
    Updating = 5,
    UpdateFinished = 6,
    WaitServer = 7,
    CheckHolidayInfo = 8,
    Succeed = 9,
    Install = 10
}

function LxPatchCtrl:Initialize()
    LxBehaviour.Initialize(self)

end

function LxPatchCtrl:Dispose()
    LxBehaviour.Dispose(self)
end

---@region 更新流程
function LxPatchCtrl:PrepareEvents()
    if self._isInitEvent then
        return
    end
    self._isInitEvent = true
    self:AddEventHandler(EventNames.UPDATE_FINISHED_WITHOUT_RELOAD, self.OnUpdateFinishedWithoutReload, self)
    self:AddEventHandler(EventNames.UPDATE_UI_READY, self.OnPrepareUIOk, self)

    self:AddEventHandler(EventNames.SDK_INIT_OK, self.OnSdkInitOk, self)
end

function LxPatchCtrl:PrepareSetVersionInfo(isUpdateAfter)
    LxResUtil.InitVersions()

    --默认版本
    local defaultAppVersion, defaultPackageVersion = PJX.AppConst.DefaultAppVersion, PJX.AppConst.DefaultPackageVersion
    --包体内置版本
    local builtinAppVersion, builtinPackageVersion = LxResUtil.GetBuiltinVersions()
    --当前版本
    local activeAppVersion, activePackageVersion = LxResUtil.GetActiveVersions()
    if LOG_INFO_ENABLED then
        if isUpdateAfter then
            printInfo("Update", FormatLogWithColor("更新结束后--》 资源版本号,内建版本:%s_%s , 当前版本: %s_%s", "ff00ffff"),
                    tostring(builtinAppVersion), tostring(builtinPackageVersion), tostring(activeAppVersion), tostring(activePackageVersion))
        else
            printInfo("Update", FormatLogWithColor("资源版本号,内建版本:%s_%s , 当前版本: %s_%s", "ff00ffff"),
                    tostring(builtinAppVersion), tostring(builtinPackageVersion), tostring(activeAppVersion), tostring(activePackageVersion))
        end

    end

    gLxServerList.defaultAppVersion = tostring(defaultAppVersion)
    gLxServerList.defaultPackageVersion = tostring(defaultPackageVersion)
    gLxServerList.activePackageVersion = tostring(activePackageVersion)
    gLxServerList.activeAppVersion = tostring(activeAppVersion)
    gLxServerList.builtinAppVersion = tostring(builtinAppVersion)
    gLxServerList.builtinPackageVersion = tostring(builtinPackageVersion)

    --10kb
    LxResUtil.SetDownloadSystemBreakpointResumeFileSize(10240)
end

function LxPatchCtrl:ReloadEnter()
    self:OnPrepareLevelOk()
end

function LxPatchCtrl:DoLevelOk()
    LNotchUtil.InitNotch()

    GF.CloseWndByName("UIBlockBlack")

    if not LGameSettings.isNotBootBackground then
        -- boot背景在这里打开，在登录场景退出时手动关闭
        GF.OpenWnd("UIBtBackground", { ignoreAlpha = true, update = true, isInitGame = true })
    end

    if not LGameSettings.isLoginAfter then
        --GF.OpenWndWait("UIBlockBlack",{0,1})
        --gLGameLogin:SetWaitEnterGame(true)
        GF.OpenWnd("UIUpte")
    end

    -- 为了提高解压速度，开启最大刷新率,在更新场景退出时，关闭最大帧率
    gLGameQuality:OpenMaxFrameRate(true)

    if CS.IsWebGL() then
        if LGameSettings.isShowWebGLDebugBtn then
            --gprint("UIWGLDebugBtn open")
            GF.OpenWndDebug("UIWGLDebugBtn")
        end
    end
end

function LxPatchCtrl:OnPrepareLevelOk()
    self:PrepareEvents()

    self:PrepareSetVersionInfo()

    self:DoLevelOk()
end

function LxPatchCtrl:DoLevelFinished()
    FireEvent(EventNames.APPLICATION_DEVICE_START)
end

function LxPatchCtrl:OnPrepareUIOk()
    --gprint("LxPatchCtrl:OnPrepareUIOk")
    --webgl版本，网络加载需要点时间会慢些，这里先不隐藏，后面再隐藏
    local isRecordGameReady = CardEHT.ManagerCenter.GameMgr:GetGameEnvVar("GameReady")
    if string.isempty(isRecordGameReady) or isRecordGameReady ~= "true" then
        LNativeHelper.CallMethod(LNativeMethod.GameReady)
    else
        CardEHT.ManagerCenter.GameMgr:SetGameEnvVar("GameReady", "false")
    end

    if not CS.IsWebGL() then
        PJXUI.UnZipUI.Instance:Hide()
    end

    self:DoLevelFinished()

    self:CheckSdkInit()
end

function LxPatchCtrl:CheckSdkInit()
    self._step = _Steps.WaitSdkInit
    if not gLSdkImpl:CallMethod(LSdkMethod.IsInit) then
        gLSdkImpl:CallMethod(LSdkMethod.CheckSdkInit)
    else
        self:CheckQueryHost()
    end
end

function LxPatchCtrl:OnSdkInitOk()
    if not gLSdkImpl:CallMethod(LSdkMethod.IsInit) then
        return
    end    
    if self._step == _Steps.WaitSdkInit then
        self:CheckQueryHost()
    end
end

function LxPatchCtrl:CheckQueryHost()
    self._step = _Steps.WaitHost
    local hostUrl
    if LGameSettings.IsQueryHost() then
        hostUrl = LGameSettings.updateUrlList[1]
    end
    if not string.isempty(hostUrl) then
        local http = MgrCenter.HttpMgr:NewHttp()
        http:InitHttp(hostUrl, function()
            self:QueryServerUpdateData()
        end)
        http:SetTimeout(3)
        http:DoGet()
        return
    end
    self:QueryServerUpdateData()
end

---step = _Steps.WaitUpdateServerInfo
function LxPatchCtrl:QueryServerUpdateData()
    self._step = _Steps.WaitUpdateServerInfo

    if gLxTKData then
        gLxTKData:OnUpdateInit()
        gLxTKData:StartServerBeginTime()
        gLxTKData:SetConnectedServerTimer()
        gLxTKData:StepConnectedServerOnce("")
        gLxTKData:StepConnectedServer("")
    end

    FireEvent(EventNames.LOGIN_UPDATE_REQ_START)

    gLxServerList:StartGetServerUpdateData(
            function () self:OnQueryServerUpdateDataSucceed() end,
            function(...)  self:OnQueryServerUpdateDataFailed(...) end
    )
end

function LxPatchCtrl:RetryQueryServerUpdateData()
    self._step = _Steps.WaitUpdateServerInfo
    gLxServerList:RetryGetServerUpdateData(
            function () self:OnQueryServerUpdateDataSucceed() end,
            function(...)  self:OnQueryServerUpdateDataFailed(...) end
    )
end

function LxPatchCtrl:OnQueryServerUpdateDataFailed(webRet, result)
    if self._step == _Steps.WaitUpdateServerInfo then
        FireEvent(EventNames.LOGIN_UPDATE_REQ_FAILURE)

        result = result or ""
        local isTimeout = string.find(result, "timeout")
        local isGameWait = string.find(result, "gamewait")
        local is404 = string.find(result, "404")
        local tipsId = 6
        if isTimeout or is404 then
            webRet = -2
            tipsId = 7
        elseif isGameWait then
            webRet = -3
            tipsId = 8
        end
        self:ShowSysTips(tipsId, nil , function(btnType)
            if btnType == 2 then
                self:RetryQueryServerUpdateData()
            else
                QuitGame()
            end
        end)
    end
end

function LxPatchCtrl:OnQueryServerUpdateDataSucceed()
    if self._step == _Steps.WaitUpdateServerInfo then
        self._step = _Steps.CheckUpdate

        FireEvent(EventNames.LOGIN_UPDATE_REQ_OK)
        gLxTKData:StepServerList(gLxServerList.webResVer)

        self:CheckUpdate()
    end
end

function LxPatchCtrl:CheckRemoteUrl()
    --远端资源地址
    local mainUrl = self:ConvertUrlToPlatform(gLxServerList.webResUrl)
    local fallbackUrl = self:ConvertUrlToPlatform(gLxServerList.webResUrl2)
    local urlList = {}
    if mainUrl then
        table.insert(urlList, mainUrl)
    end
    if fallbackUrl then
        table.insert(urlList, fallbackUrl)
    end
    if #urlList == 0 then

        return false
    end
    mainUrl = urlList[1]
    fallbackUrl = urlList[2]
    if not fallbackUrl then fallbackUrl = mainUrl end

    if not string.isempty(LGameSettings.testUrl) then
        local testUrl = LxGameSettings.testUrl
        if string.endswith(testUrl, "/") then
            testUrl = string.sub(testUrl, 1, string.len(testUrl) - string.len("/"))
        end
        mainUrl = testUrl
        fallbackUrl = testUrl
        if not string.isempty(LGameSettings.testUrl2) then
            testUrl = LxGameSettings.testUrl2
            if string.endswith(testUrl, "/") then
                testUrl = string.sub(testUrl, 1, string.len(testUrl) - string.len("/"))
            end
            fallbackUrl = testUrl
        end
    end

    LxResUtil.SetRemoteUrl(mainUrl, fallbackUrl)
    MgrCenter.PatchMgr:SetRemoteUrl(mainUrl, fallbackUrl)
    return true
end

function LxPatchCtrl:CheckUpdate()
    ---TODO
    ---region 测试代码
    --gLxServerList.webResUrl = "http://localhost:8080/x1"
    --gLxServerList.webResUrl2 = "http://localhost:8080/x1"
    --gLxServerList.webAppVersion = "1.0.0"
    --gLxServerList.webPackageVersion = "1.0.1"
    ---endregion 测试代码

    if not self:CheckRemoteUrl() then
        self:ShowSysTips(6)
        return
    end

    local webAppVersion = LxResUtil.ConvertToVersion(gLxServerList.webAppVer)
    local webPackageVersion = LxResUtil.ConvertToVersion(gLxServerList.webResVer)
    --当前版本
    local activeAppVersion, activePackageVersion = LxResUtil.GetActiveVersions()
    local builtinAppVersion, builtinPackageVersion = LxResUtil.GetBuiltinVersions()
    if LOG_INFO_ENABLED then
        printInfo("Update", "远端资源版本号:%s_%s , 当前资源版本: %s_%s",
                tostring(webAppVersion), tostring(webPackageVersion), tostring(activeAppVersion), tostring(activePackageVersion))
    end

    --WebGL 不需要热更
    if CS.IsWebGL() then
        --不需要更新， 准备进入登录界面
        self:PrepareGotoToLogin()
        return
    end

    --独占状态不更新
    if gLxServerList.isExclusiveMode then
        --FireEvent(EventNames.UPDATE_TIPS_BY_ID, 21)
        self:PrepareGotoToLogin()
        return
    end

    --检测 app版本号， web设置的， 比内建版本大需要强更
    if webAppVersion:CompareTo(builtinAppVersion) > 0 then
        self._step = _Steps.Install
        self:DoInstallApp()
        return
    else
        FireEvent(EventNames.UPDATE_NO_INSTALL)
    end

    --修复模式直接进入更新
    if LxResUtil.IsInRepairMode() then
        FireEvent(EventNames.UPDATE_REPAIR_RES_START)

        self._step = _Steps.Updating
        MgrCenter.PatchMgr:StartPatch(webAppVersion:ToString(), webPackageVersion:ToString(), true)
        return
    end

    --检测资源版本号， 比当前版本号大的需要热更
    if webPackageVersion:CompareTo(activePackageVersion) > 0 then

        gLxTKData:StepUpdateRes(0, webPackageVersion:ToString())
        FireEvent(EventNames.UPDATE_DOWNLOAD_RES_START)

        self._step = _Steps.Updating
        MgrCenter.PatchMgr:StartPatch(webAppVersion:ToString(), webPackageVersion:ToString())
        return
    end

    --不需要更新， 准备进入登录界面
    self:PrepareGotoToLogin()
end

function LxPatchCtrl:OnUpdateFinishedWithoutReload()
    --更新不需要热重载，直接结束结束
    self:PrepareGotoToLogin()
end

function LxPatchCtrl:PrepareGotoToLogin()
    self._step = _Steps.UpdateFinished

    self:QueryServerList()

    LWordMaskUtil.AutoLoad()
end

function LxPatchCtrl:QueryServerList()
    self._step = _Steps.WaitServer

    printInfoN2("patch", "Step_QueryServerListFromWeb +++")

    gLxServerList:StartGetServerList(function() self:OnQueryServerListSucceed()  end, function(...) self:OnQueryServerListFail(...) end)

    FireEvent(EventNames.LOGIN_SERVERLIST_START)
end

function LxPatchCtrl:OnQueryServerListSucceed()
    if self._step ~= _Steps.WaitServer then
        return
    end

    if gLxTKData then
        gLxTKData:OnServerList(gLxServerList.gameServerData)
    end

    FireEvent(EventNames.LOGIN_SERVERLIST_OK)


    if gLSdkImpl:CallMethod(LSdkMethod.IsGameAni) then
        self._step = _Steps.CheckHolidayInfo
        --CtrlCenter.Copyright:DoReqHolidayDataList(function()
            self:GotoLogin()
        --end)
    else
        self:GotoLogin()
    end
end

function LxPatchCtrl:OnQueryServerListFail(webRet, result)
    result = result or ""
    local isTimeout = string.find(result, "timeout")
    local isGameWait = string.find(result, "gamewait")
    local is404 = string.find(result, "404")
    local tipsId = 17
    webRet = -2
    self:ShowSysTips(tipsId, nil , function(btnType)
        if btnType == 2 then
            self:QueryServerList()
        else
            QuitGame()
        end
    end)
end

function LxPatchCtrl:GotoLogin()
    --gprint("LxPatchCtrl GotoLogin")
    self._step = _Steps.Succeed

    gLGameQuality:OpenMaxFrameRate(false)
    FireEvent(EventNames.LOGIN_SCENE_START_LOAD)

    GF.OpenWndDebug("UISisMsg")

    local param
    if CS.IsWebGL() then
        param = { isGetLaunchProgress = true }
    end

    MgrCenter.LevelMgr:LoadLevel(LevelNames.Login, nil, param)
end
---@endregion 更新流程

---@region 强更流程
function LxPatchCtrl:DoInstallApp()
    FireEvent(EventNames.UPDATE_NEED_INSTALL) -- 输出到界面提示
    if LGameSettings.platformRegion ~= LRegionConst.CHINA then
        self:ShowSysTips(2, nil, function(btnType)
            if btnType == 2 then
                self:CheckInstallURL()
            else
                QuitGame()
            end
        end)
    end

end

function LxPatchCtrl:CheckInstallURL()
    if CS.IsOSAndroid() then
        local webApkUrl = gLxServerList.webApkUrl
        local webApkUrl2 = gLxServerList.webApkUrl2
        FireEvent(EventNames.OPEN_UPDATE_INSTALL, webApkUrl)
        if string.find(webApkUrl, ".apk") then
            CS.UApplication.OpenURL(webApkUrl)
            LxTimer.DelayTimeCall(function()
                QuitGame()
            end, 1)
        else
            local urlList = {webApkUrl, webApkUrl2}
            LxHttpHelper.CheckWebDownFile(urlList, function(ret, result, url)
                if ret == CS.YXWebRet.Error then
                    LogError(tostring(ret) .. " | " .. tostring(result))
                    LogError(tostring(ret) .. " | " .. tostring(url))
                    CS.UApplication.OpenURL(webApkUrl)
                    LxTimer.DelayTimeCall(function()
                        QuitGame()
                    end, 1)
                    return
                end
                CS.UApplication.OpenURL(url)
            end)
        end

    elseif CS.IsOSIos() then
        local webIosUrl = gLxServerList.webIosUrl
        FireEvent(EventNames.OPEN_UPDATE_INSTALL, webIosUrl)
        CS.UApplication.OpenURL(webIosUrl)
        LxTimer.DelayTimeCall(function()
            QuitGame()
        end, 1)
    else
        local webApkUrl = gLxServerList.webApkUrl
        FireEvent(EventNames.OPEN_UPDATE_INSTALL, webApkUrl)
        CS.UApplication.OpenURL(webApkUrl)
        LxTimer.DelayTimeCall(function()
            QuitGame()
        end, 1)
    end
end

---@endregion 强更流程

---@region 工具函数
function LxPatchCtrl:ConvertUrlToPlatform(url)
    if string.isempty(url) then return nil end
    local platformName = "unknown"
    if CS.IsOSIos() then
        platformName = "iOS"
    elseif CS.IsOSAndroid() then
        platformName = "Android"
    elseif CS.IsOSOpenHarmony() then
        platformName = "OpenHarmony"
    elseif CS.IsOsWinOrEdit() then
        platformName = "Win"
    elseif CS.IsWebGL() then
        platformName = "WebGL"
    end
    if not string.endswith(url, "/") then
        url = url .."/"
    end
    url = url..platformName .. "/data"
    return url
end
---@endregion 工具函数

---@region 修复资源
function LxPatchCtrl:GotoRepairRes()
    self:ShowSysTips(1, nil, function(btnType)
        if btnType == 2 then
            LxResUtil.SetRepairMode(true)
            MgrCenter.LevelMgr:LoadLevel(LevelNames.Update)
        end
    end)
end
---@endregion 修复资源

---提示窗口
function LxPatchCtrl:ShowSysTips(id, strValue, callback, wndName)
    if not GameTable.UpdatePopWindowRef or not GF then
        return
    end

    local tipsRef = GameTable.UpdatePopWindowRef[id]
    if not tipsRef then
        LogError("LGameUpdate showSysTips error! id="..id)
        return
    end

    local title = ccLngText(tipsRef.title)
    local content = ccLngText(tipsRef.text)
    local btnText = ccLngText(tipsRef.btnTxt)
    local btnTextList = string.split(btnText, '|')
    local btnTile1 = btnTextList[1]
    local btnTile2 = btnTextList[2]

    if strValue then
        content = string.replace(content, strValue)
    end

    local btnType1 = tipsRef.btnType1
    local btnType2 = tipsRef.btnType2
    local nextId = tipsRef.nextId

    local function CallBtnFunByType(btnType)
        local btnTypeFuns = {
            [2] = function() QuitGame() end,
        }

        local fun = btnTypeFuns[btnType]
        if fun then
            fun()
        end
    end

    local function OnSysTipsCallback(selType)
        self._isTipsShowing = false
        if callback ~= nil then
            callback(selType)
        elseif selType == 2 then
            CallBtnFunByType(btnType2)
        else
            CallBtnFunByType(btnType1)
        end
    end

    if string.isempty(wndName) then
        wndName = "UISistemTip"
    end
    self._isTipsShowing = true
    GF.OpenWndDebug(wndName,{content = content, callFunc = OnSysTipsCallback, title = title, btnTile1 = btnTile1, btnTile2 = btnTile2})
end
